-- ===== hydrafacial-vs-regular-facial =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'HydraFacial vs regular facial — 5 differences a dermatologist sees',
  'hydrafacial-vs-regular-facial',
  'HydraFacial gets marketed as the ''best facial'', but how''s it actually different from the one at your salon? A quick dermatologist breakdown of what separates them.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "At least once a week someone asks us whether HydraFacial is just a fancy salon facial with better branding. It''s a fair question — the name has become so mainstream it''s hard to tell what''s under the hood. The short version: the device is different, the extraction method is different, and for Indian skin that matters more than most patients realise.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "1. The device does the work, not a therapist", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A HydraFacial handpiece runs a vortex of serum through a spiral tip. Exfoliation, extraction, and infusion happen in one pass, uniformly. A regular facial depends on whoever is doing it — steaming, hand extraction, a mask, rinse. Skill varies, and so do the results.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "2. The exfoliation reaches deeper without the scrubbing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The salicylic-glycolic peel step in a HydraFacial goes deeper than any manual scrub and won''t break the barrier the way aggressive scrubs do. On Indian skin prone to post-inflammatory pigmentation, that''s a meaningful safety margin.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "3. Extraction is vacuum-based, not finger-squeezed", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most PIH we see after salon facials comes from over-enthusiastic manual extraction. HydraFacial uses controlled suction — the tip does it uniformly and stops when there''s nothing more to pull out. Fewer dark marks afterwards.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "4. You see the result the same day", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "HydraFacial leaves you bright and plump within hours. A regular facial often has a 24–48 hour red phase before the glow shows up, and the payoff fades faster.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "5. The booster serums are the actual customisation", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "This is what most people miss. The HydraFacial delivery system is consistent; what changes it from patient to patient is the booster — one for pigmentation, one for hydration, one for anti-aging. Your dermatologist picks based on what the AI skin analysis flags.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "HydraFacial at Uncover starts at ₹6,999. Most patients book one every 3–4 weeks for maintenance or every 2 weeks if they''re prepping for an event.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'HydraFacial vs Regular Facial — 5 Key Differences | Uncover',
  'What actually separates HydraFacial from a salon facial? Technology, extraction method, post-session recovery, and when each is the right pick.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'hydrafacial-vs-regular-facial');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-vs-regular-facial');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-vs-regular-facial'), 1, 'Is HydraFacial actually better than a regular facial?', 'For consistent, dermatologist-grade results and zero downtime — yes. If you want an hour of relaxation at a lower price point, a traditional facial still has a place.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-vs-regular-facial'), 2, 'How often can I get a HydraFacial?', 'Every 2–4 weeks is the usual cadence. Closer together if you''re prepping for a wedding or event.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-vs-regular-facial'), 3, 'Is it safe for sensitive skin?', 'Yes, as long as your dermatologist picks a barrier-friendly booster and keeps the peel strength moderate. Tell them at intake if you''ve ever reacted to salicylic acid or fragrances.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-vs-regular-facial'), 4, 'Does HydraFacial help with active acne?', 'It clears clogged pores via the salicylic step and vacuum extraction, which helps most comedonal and mild inflammatory acne. Deeper cystic acne needs a different plan first.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-vs-regular-facial'), 5, 'How long do results last?', 'The glow holds for 2–3 weeks. The deeper benefit (texture, pore size, clarity) builds with monthly sessions.');

-- ===== what-age-to-start-botox =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'What age to start botox — a dermatologist''s honest take',
  'what-age-to-start-botox',
  'Preventative, early, corrective — these are different strategies, not different ages. How to tell which one you need, regardless of your birth year.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "''When should I start botox?'' has two honest answers — and neither is a specific age. It comes down to what your face is doing: dynamic lines that disappear when you relax, or static lines that are starting to stay.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Late 20s — if lines vanish when you stop moving, this is preventative", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Small doses every 6–12 months stop dynamic lines from etching in. Think of it as brushing your teeth. Especially relevant if you have strong habits — a heavy frown, a constantly-raised brow, or you squint at screens all day.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Mid 30s — early corrective", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If the line stays visible when your face is at rest, you''ve crossed from dynamic to early static. At this point botox both relaxes the muscle and softens the existing engraving. Combined with retinoids and daily SPF, this is where the return on investment is highest.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "40s and beyond — botox plus collagen work", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Deeper static lines don''t respond to muscle relaxation alone. You need collagen-stimulating treatment alongside — microneedling, GFC for volumising, skin boosters, or HIFU for lift. Botox alone at this stage often disappoints.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Don''t start if", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "You''re under 25 without a specific indication (strong genetic lines showing early, hyperhidrosis, migraine treatment). Pregnancy or breastfeeding — wait. Any unclear muscle or neurological condition — discuss with your doctor first.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Philosophy, not just dose", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "At Uncover we under-treat on session one and add at the 2-week review. Natural is always better than frozen. If you leave a clinic looking like you can''t raise your eyebrows, they used too much.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'What Age to Start Botox? Honest Dermatologist Guide | Uncover',
  'Preventative vs corrective botox by age and by the lines on your face. What dermatologists actually recommend in your 20s, 30s, and 40s.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'what-age-to-start-botox');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'what-age-to-start-botox');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-age-to-start-botox'), 1, 'Is botox addictive?', 'Not pharmacologically. The aesthetic habit is real though — once you''ve seen the softening, most patients choose to continue.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-age-to-start-botox'), 2, 'Can botox actually prevent wrinkles?', 'Yes, when used preventatively on dynamic lines. Reduced muscle contraction = slower etching.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-age-to-start-botox'), 3, 'Is 25 too early?', 'Not if you have visible dynamic lines. Your dermatologist will assess and recommend accordingly — it''s not a blanket yes or no.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-age-to-start-botox'), 4, 'How often do I need sessions?', '3–6 months depending on the area and how fast your body metabolises the product.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-age-to-start-botox'), 5, 'What happens if I stop?', 'Muscles regain full movement in 4–6 months. You don''t end up worse than baseline, just back to where you started.');

-- ===== does-microneedling-really-work =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Does microneedling really work? Realistic results from an Indian clinic',
  'does-microneedling-really-work',
  'Microneedling''s a category that''s been oversold by under-powered salon devices. What a dermatologist-grade device actually delivers — and what it can''t.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Microneedling''s one of the most-requested treatments in our clinic. It''s also one of the most over-sold — salons do 10-minute sessions on low-depth devices and call it microneedling. It isn''t. Here''s what the real thing can and can''t do.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The biology", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A proper microneedle creates thousands of controlled channels deep enough to trigger a wound-healing cascade. Over the next 4–8 weeks the skin lays down new collagen and elastin. That''s the engine. Depth and density of the needle pattern decide how strong the response is.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What it''s good for", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Acne scarring — boxcar, rolling, mild ice pick", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Stretch marks", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Texture and pore size", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pigmentation when paired with topicals", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Scalp hair thinning when combined with GFC or topical minoxidil", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What it can''t do", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Restore lost facial volume — that''s fillers or biostimulators", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Deep ice pick scars — those need TCA CROSS", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Treat active inflammatory acne (control it first)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Safely treat melasma if you''re reactive — heat can flare it", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why RF microneedling is often the better pick on Indian skin", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Adding radiofrequency to the needle tips roughly triples the collagen response because you''re stimulating mechanically and thermally. For Fitzpatrick IV–VI, RF microneedling produces results comparable to fractional CO2 at a fraction of the PIH risk. That''s the trade-off we explain to every patient.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Realistic timeline", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Four to six sessions spaced 4–6 weeks apart. Light improvement after session 2. Meaningful at session 4. Full collagen remodelling peaks at month 6 post-final session — which is why before/after photos are only honest if they''re at least 6 months out.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Does Microneedling Really Work? Dermatologist Answer | Uncover',
  'Honest take on microneedling — what it does, what it can''t fix, and why RF microneedling often makes a bigger difference on Indian skin.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'does-microneedling-really-work');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'does-microneedling-really-work');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-microneedling-really-work'), 1, 'How soon will I see results?', 'Skin looks fresher 1–2 weeks after each session. The collagen benefit peaks 3–6 months after the last one.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-microneedling-really-work'), 2, 'Is it painful?', 'Uncomfortable without numbing. With numbing cream, most patients rate it 3–4 out of 10. Not nothing, but manageable.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-microneedling-really-work'), 3, 'Can I use a dermaroller at home?', 'Under 0.5 mm for product penetration — yes, carefully. Anything deeper should be done by a dermatologist.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-microneedling-really-work'), 4, 'Cost in Delhi?', 'Standard microneedling at Uncover starts from ₹10,999. RF microneedling is typically 30–50% more.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-microneedling-really-work'), 5, 'Safe for dark skin?', 'Yes — we use conservative depths on Fitzpatrick V–VI and a barrier-repair post-treatment regimen to keep PIH away.');

-- ===== best-time-for-laser-hair-removal =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Best time for laser hair removal — season, body part, life stage',
  'best-time-for-laser-hair-removal',
  'When you start laser matters more in India than most clinics will tell you. Here''s how to plan around monsoon, weddings, and UV.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "India has nine months of strong UV. That''s relevant to laser hair removal in ways most patients find out the hard way — when they''ve booked three sessions and their dermatologist is now reducing the fluence because they went to Goa in between.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why season affects the result", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Laser targets melanin in the hair follicle. Fresh tan means extra melanin sitting in the top layers of skin — that absorbs the laser energy before it reaches the follicle. Lower efficacy, higher burn risk. Post-session skin is also UV-sensitive for about 10–14 days.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The October-to-February window", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Easiest months to run a clean series in Delhi NCR. UV''s low, you''re not tanning accidentally on your commute, and covering up between sessions is comfortable. March–May is workable if you''re strict with sunscreen. June through September is doable but requires more care, with conservative fluence settings.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Life-stage timing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pre-wedding — start 6–8 months out", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Post-partum — wait 6 months after delivery", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Breastfeeding — safe, but many patients prefer to wait", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Exam / work stress — fine, no contraindication", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Before a beach trip — skip the 2 weeks before and resume 2 weeks after", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Between-session discipline", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "SPF 50 daily, no direct sun for 10 days post-session, no swimming pools or saunas for 48 hours. This is non-negotiable if you want the series to finish on schedule. Patients who skip it often get a session paused or the fluence dropped.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Best Time for Laser Hair Removal in India — Season Guide | Uncover',
  'When to start laser hair removal in Delhi NCR''s climate. The window that produces the best results with the lowest pigmentation risk.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'best-time-for-laser-hair-removal');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'best-time-for-laser-hair-removal');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-time-for-laser-hair-removal'), 1, 'Can I do laser in summer?', 'Yes, with strict SPF discipline. If you''re outdoors a lot, the October–February window is easier.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-time-for-laser-hair-removal'), 2, 'How long before my wedding should I start?', '6–8 months for a complete series. 3 months if you want meaningful reduction on the most visible areas.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-time-for-laser-hair-removal'), 3, 'Can I do laser during pregnancy?', 'No. We pause for the duration. No evidence of harm, but precautionary.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-time-for-laser-hair-removal'), 4, 'Is laser safe during breastfeeding?', 'Yes. Some patients prefer to wait regardless — personal call.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-time-for-laser-hair-removal'), 5, 'Should I stop before a sunny trip?', 'Pause 2 weeks before, resume 2 weeks after. Enough for tan to fade safely.');

-- ===== laser-hair-removal-during-pregnancy =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Laser hair removal during pregnancy — can you or should you?',
  'laser-hair-removal-during-pregnancy',
  'No proof of harm, but dermatology guidelines recommend pausing. Here''s why, and what to do about unwanted hair for the next nine months.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Quick answer: we pause laser hair removal for the duration of pregnancy. There''s no evidence it causes harm. There''s also no formal safety study. In medicine, ''we don''t know'' usually means ''we don''t do it''.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why the pause is precautionary, not strict", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Laser energy sits in the skin surface — it doesn''t reach the uterus. Still, without pregnancy-specific human trials, every dermatology guideline worldwide recommends avoiding elective procedures for the nine months. We follow the same practice.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pregnancy changes the result anyway", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pregnancy hormones activate dormant follicles and can trigger melasma. If you were in the middle of a laser series when you conceived, your follicle cycle''s now on a different clock. Restarting later gives a cleaner, more predictable series.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What you can do in the meantime", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Shaving — safe, painless, no chemicals", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Electric trimmer for sensitive areas", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fragrance-free cream depilatories — skin can be more reactive during pregnancy, so patch test first", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Threading and waxing — safe; be ready for more sensitivity than usual", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Restart timeline", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Six months after delivery. Post-partum shedding settles, hormones rebalance, your scalp and hair cycle come back to baseline, and the results are more predictable.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Laser Hair Removal During Pregnancy — Is It Safe? | Uncover',
  'Why we pause laser during pregnancy, what to use instead, and when you can safely restart post-delivery.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-pregnancy');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-pregnancy');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-pregnancy'), 1, 'Is laser definitively unsafe in pregnancy?', 'No. The risk is unknown, not confirmed. The recommendation is precautionary.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-pregnancy'), 2, 'Can I do laser while trying to conceive?', 'Yes — until the point of pregnancy, it''s fine.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-pregnancy'), 3, 'I had a session before knowing I was pregnant. What now?', 'Don''t panic — no reported harm from incidental exposure. Switch to non-laser methods for the rest of the pregnancy.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-pregnancy'), 4, 'Restart after delivery?', 'Wait 6 months. Hair cycles and hormones need to rebalance.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-pregnancy'), 5, 'Does laser affect breastfeeding?', 'No — it''s safe to continue laser while breastfeeding.');

-- ===== laser-hair-removal-during-periods =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Laser hair removal during your period — safe, just more sensitive',
  'laser-hair-removal-during-periods',
  'Medically fine. Hormonally? More uncomfortable. Why skin sensitivity peaks in the pre-menstrual week and what to do about it.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Laser during your period is medically safe. What changes is comfort — hormonal shifts in the week before and during menstruation crank up skin sensitivity, so the same settings that felt like a warm tap at mid-cycle can feel like a snap.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What actually shifts in the pre-menstrual week", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Inflammation markers are higher. Pain tolerance drops. Skin holds more water, which slightly changes how the laser energy scatters. Nothing dangerous — it just means the experience is different.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Practical call", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Reschedule sensitive-area sessions (upper lip, bikini) if they fall in your pre-menstrual week", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Non-sensitive areas (legs, arms) — continue as scheduled", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Numbing cream 30 minutes before sensitive-area sessions helps", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Skip caffeine on the day — it lowers pain tolerance further", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Morning slots tend to be more comfortable than evenings", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hygiene — bikini during flow", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most clinics (including us) recommend rescheduling bikini or Brazilian sessions during heavy flow days, for comfort and hygiene. Light flow with a tampon is fine if you prefer not to delay.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Laser Hair Removal During Periods — Safe? | Uncover',
  'Is laser hair removal safe during your period? Yes. Uncomfortable? A bit. Here''s what shifts and when to reschedule.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-periods');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-periods');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-periods'), 1, 'Is laser safe during periods?', 'Yes. More uncomfortable, not more risky.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-periods'), 2, 'Will the result be the same?', 'Efficacy is unchanged. Only the sensation during the session differs.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-periods'), 3, 'Should I move my upper lip session?', 'If it lands in your pre-menstrual week and you''re sensitive to pain, yes — reschedule a week later.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-periods'), 4, 'Bikini laser during flow?', 'Most clinics defer for hygiene. Not a medical issue, a practical one.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-during-periods'), 5, 'Does post-session redness last longer?', 'Slightly, in the pre-menstrual phase. Usually still within 24 hours.');

-- ===== laser-hair-removal-with-pcos =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Laser hair removal with PCOS — what works and what to expect',
  'laser-hair-removal-with-pcos',
  'PCOS keeps activating new follicles. Laser still works — the plan is just longer, and you''ll need ongoing maintenance. Here''s the honest protocol.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PCOS hirsutism is the single most common reason women book laser in our clinic. The good news: laser works. The caveat: PCOS keeps converting vellus hair into terminal hair in the background, so your plan is longer and the maintenance is lifetime.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why PCOS plays by different rules", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Elevated androgens convert fine hair into coarse hair on the face, neck, chest, and abdomen. Laser destroys currently-active follicles. It doesn''t stop the hormonal drive creating new ones. Which is why medical treatment of PCOS itself matters as much as the laser sessions.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The PCOS-specific plan", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Blood work and endocrinology review first — confirm diagnosis, rule out thyroid and insulin issues", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "10–12 core sessions, not the usual 8", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Maintenance every 3–4 months, not every 12–18", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Spironolactone or a combined oral contraceptive if your endocrinologist prescribes", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Metformin + weight management where indicated — lowers androgens", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What results to realistically expect", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "60–75% reduction after the core 10–12 sessions. Non-PCOS patients hit 70–90% on the same timeline. The difference is real but manageable with more frequent maintenance. Facial hair responds slowest; legs and body respond about the same as any other patient.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Combination therapy is where the real shift happens", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If you''re on spironolactone or a COC alongside laser, the result is dramatically better because you''re addressing both the follicle and the hormonal signal creating new ones. Your dermatologist coordinates with your endocrinologist — that handoff matters.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Laser Hair Removal with PCOS — Treatment Plan | Uncover',
  'How laser hair removal works for PCOS-driven hirsutism — session counts, combination therapy, and what result to realistically expect.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'laser-hair-removal-with-pcos');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-with-pcos');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-with-pcos'), 1, 'Does laser actually help with PCOS?', 'Yes — the plan is longer (10–12 sessions) with ongoing maintenance every 3–4 months. The reduction is real.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-with-pcos'), 2, 'Why more sessions with PCOS?', 'PCOS keeps activating new follicles. Laser handles active ones; the hormonal drive creates more.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-with-pcos'), 3, 'Medication first or laser first?', 'Ideally parallel. Your endocrinologist manages the hormonal side; we handle the hair. Best outcomes come from both together.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-with-pcos'), 4, 'Can laser cure PCOS?', 'No. Laser reduces visible hair. PCOS itself needs hormonal and metabolic management.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-with-pcos'), 5, 'PCOS excludes me from laser?', 'No, not at all. It just shapes the plan.');

-- ===== does-laser-hair-removal-cause-cancer =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Does laser hair removal cause cancer? Direct dermatologist answer',
  'does-laser-hair-removal-cause-cancer',
  'Short answer: no. Why non-ionising light doesn''t behave like X-rays, and where the myth actually comes from.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No. Laser hair removal doesn''t cause cancer. The myth comes from the word ''radiation'' — which, used loosely, covers both X-rays and lightbulbs. Biologically they''re not the same thing.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Ionising vs non-ionising", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "X-rays, gamma rays, and some UV are ionising — they carry enough energy to break DNA bonds, which is how they cause mutations. Laser hair removal uses infrared light (typically 755 nm to 1064 nm), which is non-ionising. Not enough energy to touch DNA. No mechanism for cancer.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What the laser actually does", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The wavelength is absorbed by melanin in the hair follicle. That absorbed energy turns to heat. The heat kills the follicle. It''s localised, it doesn''t reach DNA-replicating cells in any way that could cause cancer, and this has been confirmed across 30+ years of clinical use.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Where the myth started", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Two sources. First, ''radiation'' triggers the X-ray association. Second, some old reports about IPL (different technology, broad-spectrum light, still non-ionising) talking about benign pigmented lesions looking more prominent. Neither is hair removal laser, and neither is cancer.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What is true — mole safety", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Laser should never be fired directly over a mole. Your dermatologist should assess moles in the treatment area and cover them. If a mole changes size, colour, or shape — for any reason, laser or no laser — book a skin check.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Does Laser Hair Removal Cause Cancer? Dermatologist Answer | Uncover',
  'The short answer is no. Here''s the biology behind why laser hair removal can''t cause cancer, and where the confusion started.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'does-laser-hair-removal-cause-cancer');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'does-laser-hair-removal-cause-cancer');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-laser-hair-removal-cause-cancer'), 1, 'Is laser radiation the same as X-ray radiation?', 'No. Completely different energy levels. Laser is non-ionising, X-rays are ionising.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-laser-hair-removal-cause-cancer'), 2, 'Can laser turn a mole cancerous?', 'No evidence of it. Lasers are never fired directly over a mole — the dermatologist covers them.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-laser-hair-removal-cause-cancer'), 3, 'Long-term safe?', '30+ years of clinical use, no increased cancer risk identified.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-laser-hair-removal-cause-cancer'), 4, 'What about IPL?', 'Also non-ionising. No evidence of causing cancer.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'does-laser-hair-removal-cause-cancer'), 5, 'Should I get my moles checked before laser?', 'Yes — that''s part of any proper consultation.');

-- ===== how-to-prepare-for-laser-hair-removal =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'How to prepare for laser hair removal — the 2-week checklist',
  'how-to-prepare-for-laser-hair-removal',
  'A short, specific list of what to do and avoid in the weeks before your first session. Gets you better results with less risk.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Laser prep isn''t complicated but it''s specific. Skip these and you raise the odds of burns, pigmentation, and a weaker session result.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "2 weeks before", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Stop waxing, plucking, threading, epilating — you need the hair in the follicle", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No tanning — beach, sauna, self-tanners, tanning beds", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pause strong actives on the treatment area — retinoids, AHA/BHA peels", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Tell your dermatologist about any antibiotics or photosensitising medication", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "1 week before", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Stop heat treatments (sauna, hot yoga) on target areas", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Apply SPF 50 daily to the treatment zone — indoors and out", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Stay hydrated — the session goes easier on hydrated skin", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Day of the session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Shave 12–24 hours before — not on the same morning (razor irritation)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Arrive clean — no lotion, deodorant, or makeup on the area", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Skip caffeine for sensitive-area sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Bring up at the pre-session review", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Recent sun exposure, any active cold sore or skin infection in the zone, medication started in the last 2 weeks, pregnancy or suspected pregnancy, tattoos in the area (we cover them), recent PRP or filler in the same spot.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'How to Prepare for Laser Hair Removal — Checklist | Uncover',
  'Exactly what to do and avoid in the 2 weeks before laser. Short, specific, dermatologist-approved.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'how-to-prepare-for-laser-hair-removal');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-prepare-for-laser-hair-removal');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-prepare-for-laser-hair-removal'), 1, 'Shave the same day?', 'No — 12–24 hours before is better. Lets razor irritation settle.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-prepare-for-laser-hair-removal'), 2, 'Coffee before laser?', 'For sensitive areas, skip it. Legs and arms, fine.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-prepare-for-laser-hair-removal'), 3, 'Retinol before laser?', 'Pause 5–7 days before your session.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-prepare-for-laser-hair-removal'), 4, 'Should I apply numbing cream?', 'Only what your dermatologist has prescribed. Apply 30 minutes before.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-prepare-for-laser-hair-removal'), 5, 'Can I gym the day of?', 'Yes. Skip sauna and hot yoga the 24 hours before though.');

-- ===== what-to-do-after-laser-hair-removal =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'What to do after laser — the 48-hour and 30-day aftercare',
  'what-to-do-after-laser-hair-removal',
  'How you treat the skin in the first 48 hours determines how fast redness fades and whether you end up with pigmentation. Short list, follow it.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The first 48 hours after a session decide how clean your healing looks. Here''s what we tell every patient on their way out.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hours 0–2", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Some redness and warmth is normal", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Cool compress or aloe vera for comfort", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Don''t touch or rub the area", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "First 24 hours", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Lukewarm showers only — no hot water", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No sauna, steam, or hot yoga", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No strenuous exercise", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No deodorant on underarms", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Cool compress as needed", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "First 48 hours", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No perfumed products on the treated area", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Gentle cleanser, no exfoliating anything", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Loose clothing over the area", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Stay out of swimming pools — chlorine will sting", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "First 2 weeks", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "SPF 50 daily on the treated area", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No sun tanning, no unprotected beach time", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Shaving''s fine — no waxing, plucking, threading", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Resume retinoids and acids after 5–7 days", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "When to call us", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Blisters, broken skin, pain past 24 hours, or white/very dark patches in the treated area. Rare with dermatologist-grade lasers but worth same-day review.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'What to Do After Laser Hair Removal — Aftercare Guide | Uncover',
  'Post-laser protocol — 48 hours and 30 days. Do this to avoid pigmentation and keep the series on schedule.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'what-to-do-after-laser-hair-removal');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'what-to-do-after-laser-hair-removal');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-to-do-after-laser-hair-removal'), 1, 'Moisturiser after laser?', 'Yes — plain, fragrance-free. Apply after initial redness settles.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-to-do-after-laser-hair-removal'), 2, 'Makeup?', 'Wait 24 hours for face sessions.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-to-do-after-laser-hair-removal'), 3, 'When does the hair shed?', '10–14 days. You''ll feel it pushing out. Normal.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-to-do-after-laser-hair-removal'), 4, 'Shave between sessions?', 'Yes, shaving is the only allowed method during the series.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'what-to-do-after-laser-hair-removal'), 5, 'Redness duration?', '1–4 hours for most. Beyond 24 hours, flag it.');

-- ===== hair-transplant-success-rate =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
