INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-success-rate'), 1, 'How often do transplants fail?', 'Graft failure at reputable clinics is 5–10%. Higher failure rates point to clinic quality.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-success-rate'), 2, 'Can a transplant fail entirely?', 'Total failure is very rare. Partial (thin density) is more common and usually fixable with a second session.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-success-rate'), 3, 'How many grafts will I need?', 'Norwood 3 — typically 1,500–2,500. Norwood 5+ — 3,000–5,000. Depends on donor density.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-success-rate'), 4, 'How long does it last?', 'Transplanted hair is permanent — resistant to the DHT that caused the original loss.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-success-rate'), 5, 'What affects survival most?', 'Surgical technique, patient compliance, and underlying health — smoking, diabetes, blood supply.');

