SELECT
  'Hair transplant recovery — a day-by-day timeline',
  'hair-transplant-recovery-time',
  'Recovery after FUE is faster than most patients expect. Here''s what to actually expect, day by day, through the awkward ''ugly duckling'' phase and out the other side.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most patients find FUE recovery more comfortable than they expected. What catches people off guard isn''t the pain — it''s the ''ugly duckling'' weeks between shedding and regrowth. Here''s the real timeline.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Procedure day", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "6–10 hours depending on graft count, local anaesthesia throughout. Most patients watch something or nap. You leave the same day with a protective wrap.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Days 1–2", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Mild forehead swelling (normal, gone in 2–3 days)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Scalp tenderness — a bit like sunburn", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Sleep semi-upright for the first 3 nights", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Don''t wash hair yet", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Days 3–7", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "First clinic-supervised wash on day 3", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Gentle home washing from day 4", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Scabs form around each graft", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Desk work — fine from day 3–5", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Days 7–14", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Scabs clear with gentle washing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Recipient redness fades", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Transplanted hair starts shedding around day 14–21 — expected, not a failure", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Days 30–60", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Scalp looks roughly like it did pre-transplant", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "This is the ''ugly duckling'' phase", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No visible growth yet — follicles are recovering", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Days 60–90", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "New hair starts sprouting", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Initial hairs are fine and light — they thicken over months", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Growth pattern becomes visible", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Beyond", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Month 4–6: meaningful density", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Month 9–12: final result", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Transplanted hair behaves normally — cut, colour, style as usual", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}], "direction": "ltr"}}'::jsonb,
  'Hair Transplant Recovery — Day 1 to Day 90 | Uncover',
  'What the first 90 days after FUE actually look like — downtime, scabbing, shedding, regrowth. Realistic and complete.',
  215,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'hair-transplant-recovery-time');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-recovery-time');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-recovery-time'), 1, 'Back to work when?', 'Desk work in 3–5 days. Physical labour or heavy gym, 2 weeks.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-recovery-time'), 2, 'When can I wash normally?', 'Gentle clinic-guided washing from day 3–4, normal washing from day 14.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-recovery-time'), 3, 'Is the shedding around day 14 normal?', 'Completely normal. Follicles stay, new hair grows from month 3.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-recovery-time'), 4, 'When do I see the final result?', 'Months 9–12.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hair-transplant-recovery-time'), 5, 'Exercise?', 'Light walking immediately. Full gym from week 2. Swimming from week 4.');

-- ===== best-oil-for-hair-growth =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Best oil for hair growth — honest take',
  'best-oil-for-hair-growth',
  'Castor, coconut, rosemary, onion — most claims don''t hold up under actual evidence. One oil has real clinical backing. Here''s the sorted list.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Search ''best oil for hair growth'' and you''ll find a hundred contradictory lists. Honest take: oils are mostly conditioning, not growth-promoting in the way topical minoxidil or scalp microneedling are. But one oil has real evidence, a few have decent supportive evidence, and most are hype.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The one with actual evidence — rosemary", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A 2015 clinical trial compared rosemary oil to 2% minoxidil over six months in androgenic alopecia patients. The two were comparable in regrowth, with fewer side effects from rosemary. That''s a real finding. Dilute 4–6 drops in a carrier oil (jojoba or argan), massage into the scalp 3–4 times weekly.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Good for conditioning, not growth", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Coconut oil — excellent barrier protection, reduces protein loss during washing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Almond oil — light, non-greasy, adds shine", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Jojoba — closest to natural sebum, good for dry scalps", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Argan — conditioning, smooths frizz", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Claimed benefit but weak evidence", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Castor oil — no growth evidence, too thick for regular scalp use", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Onion juice — one small study in alopecia areata; compliance is hard because of smell", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Amla — antioxidant, indirect benefit", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Honest framing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If you''re losing hair visibly, oils alone won''t fix it. The plan is: blood work to find the cause, dermatologist-supervised topical (minoxidil if indicated), and in-clinic therapy like GFC or PRP. Oils support the plan — they don''t replace it.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Best Oil for Hair Growth — Dermatologist''s List | Uncover',
  'Which hair oils actually work for growth? Rosemary''s got real evidence. Castor''s overhyped. The sorted list with references.',
  215,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'best-oil-for-hair-growth');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'best-oil-for-hair-growth');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-oil-for-hair-growth'), 1, 'Does rosemary oil really work?', 'Yes, with meaningful clinical evidence. The 2015 trial showed it comparable to 2% minoxidil at 6 months.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-oil-for-hair-growth'), 2, 'Is castor oil worth using?', 'Not as a growth promoter. It''s heavy and can cause buildup. Skip it.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-oil-for-hair-growth'), 3, 'How often should I oil?', '2–3 times a week, 30 minutes to overnight, then wash. Daily oiling causes buildup and dandruff.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-oil-for-hair-growth'), 4, 'Can oil make hair fall worse?', 'Heavy oils left too long clog follicles and worsen dandruff. Moderation is the whole game.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-oil-for-hair-growth'), 5, 'What actually works for growth?', 'Topical minoxidil, GFC or PRP, scalp microneedling, addressing root causes (iron, thyroid, PCOS). Oils support, they don''t replace.');

