)
SELECT
  'How to choose a dermatologist — 7 things to check',
  'how-to-choose-a-dermatologist',
  'Not everyone marketing themselves as a ''skin doctor'' is a dermatologist. Here''s the 7-point checklist a dermatologist would use themselves.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "India''s cosmetic skin industry mixes dermatologists, cosmetologists, salon practitioners, and franchise brands. Marketing rarely tells you which is which. Here''s the checklist a dermatologist would use themselves.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "1. Verify the MD DVL or DNB", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A dermatologist holds a Doctor of Medicine in Dermatology, Venereology and Leprosy — MD DVL — or the DNB equivalent. Verifiable on nmc.org.in. A cosmetologist isn''t a dermatologist. A nurse or technician running a laser isn''t a dermatologist either.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "2. Check the device brand", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dermatologist-grade lasers (Alma Soprano, Candela GentleMax, Lumenis UltraPulse, Fotona) cost 10–30x salon IPL. Ask the name, look it up. If they won''t tell you, that''s your answer.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "3. Transparent pricing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Itemised costs at consultation. No hidden fees. No limited-time offers pressuring you to sign same-day. The best clinics tell you the price range before you commit.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "4. Written medical history + consent", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A real dermatologist takes a full history — allergies, medications, previous treatments — and gets written consent before any procedure. Signing on the day of first injection without any of that? Walk.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "5. Before/after photography", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Standardised lighting, same angle, same distance. That''s how progress is measured objectively. No photos means no objective assessment.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "6. Honest limits, not just promises", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A good dermatologist tells you what you can''t achieve — alongside what you can. ''Permanent in one session'' or ''look 20 years younger'' are sales, not medicine.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "7. Follow-up access", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Direct line for questions. Review appointment at 2 weeks. Photo-based progress checks at 1, 3, and 6 months. That''s what clinics who care about outcomes actually do.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'How to Choose a Dermatologist — 7 Checks | Uncover',
  'The 7-point checklist for picking a dermatologist. Qualifications, equipment, transparency, red flags — before you book.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'how-to-choose-a-dermatologist');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-choose-a-dermatologist');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-choose-a-dermatologist'), 1, 'Is a cosmetologist a dermatologist?', 'No. A cosmetologist isn''t a medical doctor. A dermatologist has an MD DVL or DNB.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-choose-a-dermatologist'), 2, 'How do I verify qualifications?', 'nmc.org.in shows every registered doctor. Look for MD DVL or DNB in Dermatology.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-choose-a-dermatologist'), 3, 'Is salon laser safe?', 'Not for medical-grade treatments. Salons typically run lower-powered IPL — less effective, unsupervised.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-choose-a-dermatologist'), 4, 'What''s one filter question?', '''What''s the medical name of the device and can I look it up?'' One question, filters most clinics.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-choose-a-dermatologist'), 5, 'Should I tip?', 'No — not customary for medical consultations in India.');

-- ===== signs-you-need-a-dermatologist =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Signs you need a dermatologist, not a salon',
  'signs-you-need-a-dermatologist',
  'Six conditions that are medical, not cosmetic. Stop buying shampoos and book a consultation.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Plenty of skin and hair conditions look cosmetic but are actually medical. The distinction matters because salons can''t prescribe, diagnose, or treat them. Here are six signs it''s time to book a proper consultation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "1. Acne that persists past 3 months and leaves marks", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Salon facials manage the surface. They don''t treat underlying acne. If yours lasts longer than 3 months despite basic skincare, or leaves dark marks and scars, see a dermatologist.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "2. Hair loss beyond normal shedding", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "100 hairs a day is normal. Clumps in the shower drain, a receding hairline, visible scalp through your hair, or patchy bald spots — that''s medical.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "3. Any mole that''s changing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The ABCDE rule — Asymmetry, irregular Border, Colour change, Diameter growing, Evolution. Any changing mole warrants a check. Early skin cancer is highly treatable; late is not.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "4. Pigmentation that won''t fade", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dark patches holding steady for 3+ months despite sunscreen and basic skincare need assessment. Melasma, PIH, and sun spots need different treatments, and a salon can''t tell them apart.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "5. Rashes that stick around", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Anything lasting more than 2–3 weeks, spreading, or accompanied by fever or pain. Eczema, psoriasis, and fungal infections all get misdiagnosed at home.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "6. Any unexplained skin change", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "New bump, new discolouration, texture change, lesion you can''t explain. The cost of a consultation is vastly less than the cost of a late diagnosis.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Where salons are fine", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Monthly facials, threading, basic hair cuts, non-medical waxing. Cosmetology for mood and maintenance has real value. The line is: anything that persists, worsens, or spreads needs a dermatologist.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Signs You Need a Dermatologist — Not a Salon | Uncover',
  'Six medical conditions that salons can''t treat. When to stop DIY and see a dermatologist.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'signs-you-need-a-dermatologist');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'signs-you-need-a-dermatologist');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'signs-you-need-a-dermatologist'), 1, 'Can a salon treat acne?', 'No. They can manage appearance. True acne treatment needs prescription medication and supervised procedures.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'signs-you-need-a-dermatologist'), 2, 'Is melasma treatable?', 'Yes — with Q-switch laser, prescription topicals, and strict SPF. Salon bleaching creams usually worsen it.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'signs-you-need-a-dermatologist'), 3, 'When for hair loss?', 'At the first sign of persistent shedding beyond normal. Early intervention wins.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'signs-you-need-a-dermatologist'), 4, 'Is salon skincare safe in pregnancy?', 'Basic facials mostly yes. Any chemical peel, light therapy, or retinoid — have a dermatologist review.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'signs-you-need-a-dermatologist'), 5, 'How often should I see one?', 'Healthy adults — once a year. More often if you''re on an active plan.');

-- ===== cosmetologist-vs-dermatologist =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Cosmetologist vs dermatologist — why the distinction matters',
  'cosmetologist-vs-dermatologist',
  'In India the terms get used interchangeably. The qualifications, the legal scope, and what each can actually do — entirely different.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Marketing in India often uses ''cosmetologist'' and ''dermatologist'' as if they''re the same. Medically and legally, they''re not.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dermatologist", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "MBBS + MD in Dermatology, Venereology and Leprosy — or the DNB equivalent. 10+ years of medical training. Registered with the NMC. Can diagnose and treat medical conditions, prescribe medication, do surgical procedures, operate medical-grade laser and injectables.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Cosmetologist", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Non-medical practitioner with a diploma or certificate in cosmetology — 6 months to 2 years of training typically. Legally can''t diagnose medical conditions, prescribe, or perform medical procedures. Can do facials, beauty treatments, and aesthetic procedures within training scope.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Scope at a glance", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Skin cancer screening — dermatologist only", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Prescription medication — dermatologist only", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Medical laser (Q-switch Nd:YAG, fractional CO2) — dermatologist only", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Botox and fillers — medically a doctor, practically a dermatologist or plastic surgeon", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "TCA or deep chemical peels — dermatologist", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Salicylic or glycolic peels at safe concentrations — cosmetologist with training", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 7, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hair transplant — dermatologist or plastic surgeon", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 8, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Facial and extraction — cosmetologist is fine", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why it matters in India", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Regulatory enforcement on who can operate medical lasers is inconsistent. Many clinics run medical-grade equipment with staff who aren''t legally qualified. The NMC register (nmc.org.in) is public — a dermatologist will be listed, a cosmetologist won''t.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What this means for you", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Facials, threading, waxing — a cosmetologist''s fine. Laser, botox, fillers, acne treatment, pigmentation, hair loss — insist on a dermatologist.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Cosmetologist vs Dermatologist — Key Differences | Uncover',
  'Cosmetologist and dermatologist are different professions. What each can legally do, and when you need which.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'cosmetologist-vs-dermatologist');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'cosmetologist-vs-dermatologist');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'cosmetologist-vs-dermatologist'), 1, 'Can a cosmetologist do botox?', 'No. Legally, only a medical doctor injects. Practically, you want a dermatologist or plastic surgeon.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'cosmetologist-vs-dermatologist'), 2, 'Cosmetologist doing laser?', 'Some low-powered IPL in salons, but medical laser needs a dermatologist.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'cosmetologist-vs-dermatologist'), 3, 'How to verify?', 'Check nmc.org.in. Any MD DVL or DNB Dermatology is listed.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'cosmetologist-vs-dermatologist'), 4, 'Is a cosmetologist useful at all?', 'Yes, for non-medical beauty services — facials, waxing, threading, styling.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'cosmetologist-vs-dermatologist'), 5, 'Can cosmetologists diagnose acne?', 'No. They can spot it. Diagnosis and prescription need a dermatologist.');

-- ===== fitzpatrick-skin-type-test =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Fitzpatrick skin type test — find yours, understand why it matters',
  'fitzpatrick-skin-type-test',
  'Your Fitzpatrick type decides what''s safe for you in laser, peels, and pigmentation treatment. Here''s the 5-question test.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The Fitzpatrick scale groups skin into six types based on how it reacts to sun. Every dermatologist uses it to plan laser fluence, peel strength, and pigmentation protocols. Skip it and the odds of burns and hyperpigmentation go up sharply.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The 5-question self test", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Rate each question 0–4 and add up:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Natural (untanned) skin colour — 0=ivory, 4=dark brown", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Eye colour — 0=light blue/grey, 4=brownish black", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Natural hair colour — 0=red/light blonde, 4=black", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Freckles on unexposed skin — 0=many, 4=none", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Ethnic background — 0=white, 4=dark brown/black", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Total and match:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "0–7 = Type I — very fair, always burns, never tans", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "8–16 = Type II — fair, burns easily, tans minimally", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "17–25 = Type III — light brown, burns moderately, tans gradually", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "25–30 = Type IV — olive to light brown, burns minimally, tans well", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "31–35 = Type V — brown, rarely burns, tans dark", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "36+ = Type VI — dark brown to black, never burns", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why the clinical team needs this", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For laser: I–II tolerate higher fluence; V–VI need pigment-specific wavelengths (Nd:YAG 1064 nm). For chemical peels: deep peels safe only for I–III; IV–VI need superficial-to-medium peels plus pigment prophylaxis. For pigmentation: darker skin types need gentler settings and test spots.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Where most Indian patients sit", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most Indian patients fall in III–V. South Indian and darker North Indian patients often V. Type VI less common here but seen. Self-tests can be one type off — your dermatologist confirms at consultation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Fitzpatrick Skin Type Test — Find Your Type | Uncover',
  'A 5-question test to find your Fitzpatrick type. Why dermatologists use it for every laser and peel decision.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'fitzpatrick-skin-type-test');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'fitzpatrick-skin-type-test');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'fitzpatrick-skin-type-test'), 1, 'What Fitzpatrick type are Indians?', 'Most are III–V. Lighter North Indian complexions III–IV, darker complexions IV–V.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'fitzpatrick-skin-type-test'), 2, 'Can it change?', 'No. It''s your natural type, untanned. Current tan is temporary.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'fitzpatrick-skin-type-test'), 3, 'Why do dermatologists ask?', 'To pick safe laser settings, peel strength, and pigmentation protocols. Wrong settings for your type is the top cause of PIH.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'fitzpatrick-skin-type-test'), 4, 'Is V–VI safe for laser?', 'Yes — with Nd:YAG 1064 nm and conservative fluence. Always test spot first.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'fitzpatrick-skin-type-test'), 5, 'Accurate self-test?', 'Usually within one type. Dermatologist confirms.');

-- ===== hydrafacial-side-effects =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'HydraFacial side effects — normal vs not normal',
  'hydrafacial-side-effects',
  'HydraFacial has one of the cleanest safety profiles in cosmetic dermatology. That doesn''t mean zero reactions — here''s what''s expected and what to flag.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "HydraFacial has one of the cleanest safety profiles in cosmetic dermatology — most patients walk out with zero issues. That said, it''s still a procedure, and a few reactions are possible.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Normal and expected", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Mild redness for 1–2 hours post-treatment", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Slight tingling during the serum infusion", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Skin feeling tight or dry for 24 hours — expected post-exfoliation", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Small pimples in week 1 — usually pre-existing congestion clearing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Less common but still normal", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Purging — a burst of breakouts in the first 1–2 sessions as deep congestion clears", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Temporary rash if sensitive to a specific booster serum", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Mild bruising at a vacuum-extraction point if skin''s fragile", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Rare — flag these", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Allergic reaction to a booster — itching, hives, widespread redness", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Worsening cystic acne — protocol needs adjustment", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hyperpigmentation on very reactive skin — rare with dermatologist protocols", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "When to call", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Redness beyond 6 hours, itching or hives, any blistering, or unusual darkening in the treated area. Rare but worth same-day review.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Who should skip it", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Active cold sore or herpes outbreak on the face", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Active severe cystic acne (until controlled)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "First-trimester pregnancy (precautionary — most ingredients are safe, but it''s elective)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Known allergies to any booster ingredient (flag at consultation)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}], "direction": "ltr"}}'::jsonb,
  'HydraFacial Side Effects — Normal vs Abnormal | Uncover',
  'What HydraFacial side effects to expect, what''s normal, and when to call your clinic. Safe for most skin types.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'hydrafacial-side-effects');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-side-effects');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-side-effects'), 1, 'Can HydraFacial cause breakouts?', 'Purging in sessions 1–2 is normal — deep congestion coming up. Persistent worsening is uncommon, worth flagging.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-side-effects'), 2, 'Safe in pregnancy?', 'Usually after first trimester. Skip retinoid and salicylic booster serums during.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-side-effects'), 3, 'Redness duration?', '1–2 hours typical. Beyond 6 hours is unusual.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-side-effects'), 4, 'Can it cause pigmentation?', 'Rare with dermatologist-led protocols. More likely with aggressive salon versions.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'hydrafacial-side-effects'), 5, 'Safe for rosacea?', 'Yes, with gentle settings and appropriate boosters. Some tolerate well, others get temporary flushing.');

-- ===== chemical-peel-side-effects =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Chemical peel side effects by depth — superficial, medium, deep',
  'chemical-peel-side-effects',
  'Superficial peels barely have downtime. Deep peels need 2 weeks of recovery. Here''s what''s normal at each depth.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Chemical peels are classified by depth — superficial, medium, deep — and each has a different reaction profile. Knowing what to expect prevents unnecessary panic and helps catch the real problems early.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Superficial peels (glycolic, salicylic, mandelic)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Expected: mild redness for 1–2 hours, slight tingling during application, 1–3 days of mild flaking. Stinging during application is normal. Burning is not — if it''s burning, tell the dermatologist immediately.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Medium peels (Jessner''s, 20–35% TCA)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Expected: visible redness for 2–3 days, peeling from day 3 to day 7, mild tightness. Mild eyelid swelling is possible, brief itching during healing is common, and treated areas may darken temporarily if SPF is skipped.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Deep peels (phenol, high-concentration TCA)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Expected: significant redness, peeling from day 2 to day 10–14, deep skin regeneration. Done infrequently and under medical supervision. Recovery takes 2–3 weeks — plan around it.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Indian skin considerations", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fitzpatrick IV–VI has higher PIH risk. Your dermatologist should pre-treat you with brightening serums for 2–4 weeks before a medium or deep peel and use conservative depths. Skipping either step is the common reason peels go wrong here.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Red flags", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Burning past the application window", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Swelling increasing beyond day 2", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Sharp pain or blistering", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Irregular scabbing (scabbing should be uniform)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Darkening beyond what was expected", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Post-peel SPF 50 daily is non-negotiable on Indian skin. The most common way peels go wrong is skipped sunscreen.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Chemical Peel Side Effects — By Peel Type | Uncover',
  'What''s normal for superficial, medium, and deep chemical peels. When to worry, when to relax.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'chemical-peel-side-effects');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'chemical-peel-side-effects');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'chemical-peel-side-effects'), 1, 'How long does peeling last?', 'Superficial: 1–3 days. Medium: 5–7 days. Deep: 10–14 days.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'chemical-peel-side-effects'), 2, 'Can peels cause permanent damage?', 'Rarely, with appropriate depth and experienced dermatologist. Home peels without supervision are the common cause of harm.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'chemical-peel-side-effects'), 3, 'Can Indian skin do medium/deep peels?', 'Yes, with pre-treatment, right peel selection, and post-peel pigmentation management.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'chemical-peel-side-effects'), 4, 'How often?', 'Superficial every 4 weeks. Medium every 3–6 months. Deep once a year or less.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'chemical-peel-side-effects'), 5, 'Will peels fix acne scars?', 'Peels soften and brighten but rarely fully remove textural scars. Combined with microneedling or fractional laser, they perform better.');

COMMIT;
